#include <bits/stdc++.h>
using namespace std;
int main(){
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    string s, p; cin >> s >> p;
    string t = p + '#' + s;
    int n = (int)t.size();
    vector<int> pi(n, 0);
    for (int i = 1; i < n; i++) {
        int j = pi[i-1];
        while (j > 0 && t[i] != t[j]) j = pi[j-1];
        if (t[i] == t[j]) j++;
        pi[i] = j;
    }
    long long cnt = 0;
    for (int i = (int)p.size() + 1; i < n; i++) if (pi[i] == (int)p.size()) cnt++;
    cout << cnt << '\n';
}
